const mid = msg.machine_id || msg.topic;
return [
    { machine_id: mid, topic: mid, _walker: 'cpu', payload: '' },
    { machine_id: mid, topic: mid, _walker: 'storage', payload: '' },
    { machine_id: mid, topic: mid, _walker: 'net32', payload: '' },
    { machine_id: mid, topic: mid, _walker: 'net64', payload: '' },
    { machine_id: mid, topic: mid, _walker: 'temp', payload: '' }
];

if (!msg.payload || !Array.isArray(msg.payload)) return null;

const flatData = msg.payload.flat();
msg.payload = null;

let cpuTotal=0, coreCount=0;
let ramTotalMB=0, ramUsedMB=0, diskTotalGB=0, diskUsedGB=0;
let netRxBytes=0, netTxBytes=0, netRxErrors=0, netRxDrops=0, netIfStatus=1, maxTemp=0;
const disks={}, ifaces={};

for (let i = 0; i < flatData.length; i++) {
    const item = flatData[i];
    if (!item || !item.oid) continue;
    const oid = String(item.oid);
    const val = item.value;

    if (oid.startsWith('1.3.6.1.2.1.25.3.3.1.2.')) {
        const v = Number(val); if(Number.isFinite(v)){ cpuTotal+=v; coreCount++; }
    }
    else if (oid.startsWith('1.3.6.1.2.1.25.2.3.1.')) {
        const parts = oid.split('.'); const idx = parts.pop(); const mt = parts.pop();
        if (!disks[idx]) disks[idx] = { type: '', descr: '', au: 0, size: 0, used: 0 };
        if (mt === '2') disks[idx].type = String(val);
        else if (mt === '3') disks[idx].descr = String(val).toUpperCase();
        else if (mt === '4') disks[idx].au = Number(val) || 0;
        else if (mt === '5') disks[idx].size = Number(val) || 0;
        else if (mt === '6') disks[idx].used = Number(val) || 0;
    }
    else if (oid.startsWith('1.3.6.1.2.1.31.1.1.1.6.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].rx64=Number(val)||0; netRxBytes+=ifaces[idx].rx64;
    }
    else if (oid.startsWith('1.3.6.1.2.1.31.1.1.1.10.')){
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].tx64=Number(val)||0; netTxBytes+=ifaces[idx].tx64;
    }
    else if (oid.startsWith('1.3.6.1.2.1.2.2.1.2.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'',rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].name=String(val);
    }
    else if (oid.startsWith('1.3.6.1.2.1.2.2.1.10.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].rx32=Number(val)||0; if(netRxBytes===0) netRxBytes+=ifaces[idx].rx32;
    }
    else if (oid.startsWith('1.3.6.1.2.1.2.2.1.16.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].tx32=Number(val)||0; if(netTxBytes===0) netTxBytes+=ifaces[idx].tx32;
    }
    else if (oid.startsWith('1.3.6.1.2.1.2.2.1.14.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].err+=Number(val)||0; netRxErrors+=Number(val)||0;
    }
    else if (oid.startsWith('1.3.6.1.2.1.2.2.1.13.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        ifaces[idx].drop+=Number(val)||0; netRxDrops+=Number(val)||0;
    }
    else if (oid.startsWith('1.3.6.1.2.1.2.2.1.8.')) {
        const idx=oid.split('.').pop();
        if(!ifaces[idx]) ifaces[idx]={name:'port_'+idx,rx64:0,tx64:0,rx32:0,tx32:0,err:0,drop:0,status:1};
        const st=Number(val); if(st===2){ ifaces[idx].status=2; netIfStatus=2; }
    }
    else if (oid.startsWith('1.3.6.1.4.1.2021.13.16.2.1.7.')) {
        const t = Number(val); if (Number.isFinite(t) && t > maxTemp) maxTemp = t;
    }
}

flatData.length = 0;

for (const idx in disks) {
    const d = disks[idx];
    if (!d.au || !d.size) continue;
    const sb = d.size * d.au, ub = d.used * d.au, ds = d.descr;
    if (d.type.includes('25.2.1.2') || ds.includes('MEMORY')) { ramTotalMB += sb / 1048576; ramUsedMB += ub / 1048576; }
    else if (d.type.includes('25.2.1.4') || ds.includes('C:') || ds.includes('/')) { diskTotalGB += sb / 1073741824; diskUsedGB += ub / 1073741824; }
}

const now = Date.now();
const mid = String(msg.topic).replace(/'/g, "''");
const prevIfaces = flow.get('ifaces_prev_'+mid) || {};
const prevTs = flow.get('ts_prev_'+mid) || (now - 10000);
const elapsedSec = (now - prevTs) / 1000;
const finalIfaces = {};
let rxAll = 0, txAll = 0;

for(const idx in ifaces){
    const iface=ifaces[idx]; 
    let rxMbps=0, txMbps=0;
    if(iface.status === 2) { rxMbps=0; txMbps=0; }
    else if(elapsedSec >= 2 && prevIfaces[idx]) {
        const rx=iface.rx64||iface.rx32; const tx=iface.tx64||iface.tx32;
        const prevRx=prevIfaces[idx].rx64||prevIfaces[idx].rx32; 
        const prevTx=prevIfaces[idx].tx64||prevIfaces[idx].tx32;
        let rxDiff = rx - prevRx; let txDiff = tx - prevTx;
        if(rxDiff < 0) rxDiff += 18446744073709552000;
        if(txDiff < 0) txDiff += 18446744073709552000;
        rxMbps = Number(((rxDiff*8)/(elapsedSec*1000000)).toFixed(2));
        txMbps = Number(((txDiff*8)/(elapsedSec*1000000)).toFixed(2));
    } else if (prevIfaces[idx]) {
        rxMbps = prevIfaces[idx].rx_mbps || 0;
        txMbps = prevIfaces[idx].tx_mbps || 0;
    }
    finalIfaces[iface.name||'port_'+idx] = { rx_mbps:rxMbps, tx_mbps:txMbps, errors:iface.err, drops:iface.drop, status:iface.status===1?'UP':'DOWN' };
    rxAll += rxMbps; txAll += txMbps;
}

flow.set('ifaces_prev_'+mid, ifaces);
flow.set('ts_prev_'+mid, now);

const safeNum = (v) => Number.isFinite(v) && v >= 0 && v < 1e15 ? Number(v.toFixed(2)) : 0;
const ts = new Date().toISOString();
const ifaceJson = String(JSON.stringify(finalIfaces)).replace(/'/g, "''");

msg.query = `INSERT INTO public.machine_telemetry ("time", machine_id, cpu_cores, cpu_load_percent, ram_total_mb, ram_used_mb, ram_free_mb, disk_total_gb, disk_used_gb, disk_free_gb, net_rx_bytes, net_tx_bytes, net_rx_errors, net_rx_drops, net_if_status, temp_c, rx_mbps, tx_mbps, interface_metrics) VALUES ('${ts}', '${mid}', ${coreCount}, ${coreCount > 0 ? safeNum(cpuTotal/coreCount) : 0}, ${safeNum(ramTotalMB)}, ${safeNum(ramUsedMB)}, ${safeNum(ramTotalMB - ramUsedMB)}, ${safeNum(diskTotalGB)}, ${safeNum(diskUsedGB)}, ${safeNum(diskTotalGB - diskUsedGB)}, ${netRxBytes}, ${netTxBytes}, ${netRxErrors}, ${netRxDrops}, ${netIfStatus}, ${maxTemp}, ${safeNum(rxAll)}, ${safeNum(txAll)}, '${ifaceJson}'::jsonb);`;

msg.payload = { machine_id: mid, ts: ts, rxMbps: rxAll, errors: netRxErrors, status: netIfStatus, temp: maxTemp };
return msg;
